--"C:\Program Files\PostgreSQL\17\bin\psql.exe" -U postgres -d gamemag -f makedatabase.sql
\encoding UTF8

-- 1) ส่วนเสริมที่ต้องใช้สำหรับฟังก์ชัน crypt()
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- 2) ตารางผู้ใช้
CREATE TABLE IF NOT EXISTS users (
  user_id   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  fullname  TEXT    NOT NULL,
  username  TEXT    UNIQUE NOT NULL,
  password  TEXT    NOT NULL,
  role      TEXT    NOT NULL DEFAULT 'user',
  status    BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 3) ตารางตั้งค่าโฮมเพจ (1 แถว id=1)
CREATE TABLE IF NOT EXISTS home_config (
  id         INTEGER PRIMARY KEY,
  data       JSONB NOT NULL DEFAULT '{}'::jsonb,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

INSERT INTO home_config (id, data)
VALUES (1, '{}'::jsonb)
ON CONFLICT (id) DO NOTHING;

-- 4) ตารางบทความ
CREATE TABLE IF NOT EXISTS articles (
  id           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  slug         TEXT UNIQUE NOT NULL,
  title        TEXT NOT NULL,
  content      TEXT NOT NULL,
  image_url    TEXT,
  badge        TEXT NOT NULL DEFAULT 'เกมใหม่',
  published_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- 4.1 ดัชนีเสริม (ช่วยค้นหาตามเวลา)
CREATE INDEX IF NOT EXISTS idx_articles_published_at ON articles (published_at DESC);

-- 5) ตารางประวัติการแก้ไขบทความ (support feature “revision” ที่โค้ดใช้อยู่)
CREATE TABLE IF NOT EXISTS article_revisions (
  rev_id       BIGSERIAL PRIMARY KEY,
  slug         TEXT NOT NULL,
  title        TEXT NOT NULL,
  content      TEXT NOT NULL,
  image_url    TEXT,
  badge        TEXT,
  published_at TIMESTAMPTZ,
  edited_by    TEXT,                  -- เก็บชื่อผู้ใช้ที่แก้ไข (username)
  edited_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_article_revisions_slug ON article_revisions (slug);
CREATE INDEX IF NOT EXISTS idx_article_revisions_edited_at ON article_revisions (edited_at DESC);

-- 6) ผู้ใช้เริ่มต้น (แอดมิน) — เปลี่ยนรหัสผ่านทีหลังได้
INSERT INTO users (fullname, username, password, role, status)
VALUES ('Admin', 'admin', crypt('12345678', gen_salt('bf')), 'admin', TRUE)
ON CONFLICT (username) DO NOTHING;

-- 7) บทความตัวอย่าง
INSERT INTO articles (slug, title, content, image_url, badge, published_at) VALUES
('แพตช์โน้ต VALORANT 11.08', 'แพตช์โน้ต VALORANT 11.08','<h1>VALORANT แพตช์ปลายปี</h1><h2>ทุกแพลตฟอร์ม</h2><p>แพตช์ปรับสมดุลในช่วงปลายปีของเรามีเป้าหมายเพื่อปรับเปลี่ยนการทำงานร่วมกันระหว่างแผนที่ อาวุธ และเอเจนท์ การปรับเปลี่ยนในแพตช์นี้ออกแบบมาเพื่อช่วยเสริมสิ่งที่เราเรียกว่า “การโต้ตอบเชิงแข่งขัน” ซึ่งหมายถึงการโต้ตอบระหว่างฝ่ายโจมตีและฝ่ายป้องกันในแต่ละรอบ ซึ่งสร้างความได้เปรียบให้กับฝ่ายที่ปรับตัวและใช้กลยุทธ์ได้ดี</p><p>ทักษะของผู้เล่นและผลกระทบจากสกิลต่าง ๆ ได้เพิ่มมากขึ้นเมื่อเวลาผ่านไป แต่บางครั้งการใช้สกิลแบบไม่ประสานงานกลับส่งผลต่อรูปเกมได้พอ ๆ กับการเล่นเชิงกลยุทธ์ที่วางแผนมาอย่างดี ทำให้โอกาสสำคัญในการแก้เกมลดลง และลดความซับซ้อนเชิงกลยุทธ์ที่เราต้องการใน VALORANT การเปลี่ยนแปลงเหล่านี้เน้นไปที่การรักษาสมดุลระหว่างการยิงปืนและการใช้สกิล</p><h2>อัปเดตเอเจนท์</h2><h3>ทั่วไป</h3><p>การอัปเดตเอเจนท์ในแพตช์นี้มุ่งเน้นไปที่การสนับสนุนให้ผู้เล่นฝึกใช้สกิลได้ชำนาญยิ่งขึ้น พร้อมทั้งลดขนาดของสกิลอัลติเมทใหญ่ ๆ และทำให้ดีบัฟของเกมสอดคล้องกันมากขึ้น เช่น สถานะถูกจำกัดการมองเห็น, สถานะกระทบกระเทือน และ Stim</p><h4>สถานะถูกจำกัดการมองเห็น</h4><ul><li>Prowler ของ Fade, Paranoia ของ Omen, Leer ของ Reyna, Seeker ของ Skye</li><li>รัศมีมองเห็นได้เพิ่มขึ้น: 5 → 7 เมตร</li></ul><h4>สถานะกระทบกระเทือน</h4><ul><li>Fault Line ของ Breach, Wingman ของ Gekko, Relay Bolt ของ Neon, Nova Pulse ของ Astra</li><li>ระยะเวลาสถานะกระทบกระเทือนลดลง: 3.5 → 2.5 วินาที</li></ul><h4>ปรับ Stim ให้มีมาตรฐานเดียวกัน</h4><ul><li>Stim Beacon ของ Brimstone, NULL/CMD ของ KAY/O, Empress ของ Reyna</li><li>ตัวคูณเวลารีโหลดเร็วขึ้น: 90%</li><li>ตัวคูณอัตรายิงเพิ่มขึ้น: 10%</li><li>ตัวคูณเวลาชักอาวุธ: 90%</li><li>ตัวคูณความเร็วฟื้นตัวอาวุธ: 10%</li></ul><h3>Initiator</h3><p>ออกแบบให้ Initiator เป็นเอเจนท์ที่เหมาะกับการเปิดมุมและเปิดทางให้กับทีม สกิลเฉพาะตัวต้องอาศัยการประสานงานและกะจังหวะเวลาที่รอบคอบ</p><h4>Breach</h4><ul><li>Fault Line: คูลดาวน์ 40 → 60 วินาที, ระยะเวลาสถานะกระทบกระเทือน 3.5 → 2.5 วินาที</li><li>Flashpoint: ระยะเวลาแฟลช 2 → 2.25 วินาที</li><li>Rolling Thunder: ความกว้าง 23 → 18 เมตร, ระยะเวลาสถานะกระทบกระเทือน 6 → 4 วินาที, อัลติเมท 9 → 8</li></ul><h4>Fade</h4><ul><li>Haunt: คูลดาวน์ 40 → 60 วินาที, ระยะเวลาทำงาน 2 → 1.5 วินาที</li><li>Prowler: ระยะมองเห็น 5 → 7 เมตร</li><li>Nightfall: ระยะเวลาถูกจำกัดการได้ยินลดลง 12 → 8 วินาที, ความกว้าง 24 → 20 เมตร</li></ul><h3>Controller</h3><ul><li>Astra: Gravity Well ระยะเวลาติดเปราะบาง 5 → 2.5 วินาที, คูลดาวน์ 45 → 60 วินาที</li><li>Astra: Nova Pulse ระยะเวลาสถานะกระทบกระเทือน 3.5 → 2.5 วินาที, คูลดาวน์ 45 → 60 วินาที</li><li>Brimstone: Stim Beacon อัตรายิงเพิ่มขึ้นลดลง 15 → 10%, ความเร็วเคลื่อนที่เพิ่มขึ้น 15 → 10%</li><li>Omen: Dark Cover คูลดาวน์ 30 → 40 วินาที</li></ul><h3>Sentinel</h3><ul><li>Vyse: Arc Rose ระยะเวลาแฟลช 2.25 → 2.0 วินาที, คูลดาวน์ปรับเล็กน้อย</li><li>Shear: กับดักกำแพงเกิดทันทีเมื่อศัตรูเข้า-ออกพื้นที่, ศัตรูได้ยินเสียงแจ้งเตือนเฉพาะศัตรู</li><li>Razorvine: พลังชีวิตลดลง 40 → 20</li></ul><h3>แผนที่</h3><p>ส่งเสริมให้ทั้งสองทีมเล่นในไซต์มากขึ้น และทำให้การติดตั้ง Spike ใน Main มีความเสี่ยงมากขึ้น</p><h4>Pearl - B-Site</h4><ul><li>ลบแนวยิงจากระยะไกลออกจาก B Long</li><li>ปรับเปลี่ยนตำแหน่งกำบังในและรอบ ๆ ไซต์</li></ul><img src="https://cmsassets.rgpub.io/sanity/images/dsfx7636/news/0089861662b41c8d5c3c4f1c14cb4d1937936105-915x515.webp?auto=format&fit=fill&q=80&w=915"><h3>Abyss</h3><p>หลังจากเห็นพัฒนาการของแผนที่ตลอดปีที่ผ่านมา เราสังเกตเห็นมีกลยุทธ์ที่โดดเด่นเกิดขึ้นมากมาย และพบจุดที่อาจปรับปรุงได้ โดยเน้นไปที่การเสริมความแข็งแกร่งให้กับฝ่ายป้องกันและปรับปรุงเส้นทางการเคลื่อนที่ให้ดียิ่งขึ้น</p><h4>B-Site</h4><ul><li>การเล่นในไซต์ถือเป็นเรื่องยากสำหรับทั้งสองทีม</li><li>ฝ่ายป้องกันมีปัญหากับการคุมไซต์ในช่วงเริ่มต้น</li><li>ฝ่ายโจมตีมีปัญหาในการป้องกัน Spike ในช่วงหลังติดตั้ง Spike และรู้สึกว่าถูกบีบให้ต้องติดตั้ง Spike เพื่อเล่นใน Main</li><li>ปรับปรุงการเล่นในไซต์สำหรับทั้งสองทีม และเพิ่มความเสี่ยงในการเล่นใน Main หลังติดตั้ง Spike</li></ul><h4>Mid</h4><ul><li>ปรับปรุงโถงทางเดินใน Mid ให้ทั้งสองทีมมีเส้นทางการเคลื่อนที่ที่รวดเร็วขึ้น</li><li>ปรับปรุงเส้นทางมุ่งหน้าไปยัง B Main เพื่อให้ทั้งสองทีมเคลื่อนที่ผ่านแผนที่ได้ราบรื่นยิ่งขึ้น</li></ul><img src="https://cmsassets.rgpub.io/sanity/images/dsfx7636/news_live/53698d442a14b5a6be643d53eb970ac16442cb38-930x522.png?auto=format&fit=fill&q=80&w=930"><h2>อัปเดตรายชื่อแผนที่</h2><ul><li>PEARL และ SPLIT เข้าสู่คิว COMPETITIVE และ DEATHMATCH</li><li>LOTUS และ ASCENT ออกจากคิว COMPETITIVE และ DEATHMATCH</li></ul><h2>อัปเดตอาวุธ</h2><p>เราตั้งเป้าที่จะทำให้การยิงปืนใน VALORANT รู้สึกคุ้มค่าเมื่อฝึกจนชำนาญ แต่ละอาวุธมีเอกลักษณ์พร้อมจุดแข็งและจุดอ่อนของตนเอง</p><h3>เฉพาะ PC</h3><h4>ปืนไรเฟิล</h4><p>ปรับเปลี่ยนการกราดยิงเพื่อให้สมดุลระหว่างยิงทีละนัด, ยิงเป็นชุด และการกราดยิง โดยโอกาสและระยะเวลาเบี่ยงทิศทางกระสุนถูกปรับ</p><ul><li>Bulldog: ระยะเวลาเบี่ยงทิศทางเพิ่ม 0.37 → 0.6 วินาที, โอกาสเบี่ยงทิศทางเพิ่ม 6% → 10%</li><li>Phantom: ระยะเวลา 0.37 → 0.6 วินาที, โอกาสเบี่ยงทิศทาง 6% → 10%, จำนวนกระสุนไม่เบี่ยงเพิ่ม 6 → 8 นัด</li><li>Vandal: ระยะเวลา 0.37 → 0.6 วินาที, โอกาสเบี่ยงทิศทาง 6% → 10%, จำนวนกระสุนไม่เบี่ยงเพิ่ม 4 → 6 นัด</li></ul><h4>ปืนกลมือ (SMG)</h4><ul><li>Spectre: การกระจายลดลง 1.5 → 1.3, ยิงทีละนัดเพิ่ม 2 → 3, ระยะเวลาเบี่ยงทิศทางเพิ่ม 0.18 → 0.28 วินาที, จำนวนกระสุนไม่เบี่ยงเพิ่ม 4 → 5 นัด</li><li>Stinger: การกระจายเพิ่ม 1.3 → 1.5, การกระจายเกิดเร็วขึ้นจาก 7 → 6 นัด, แรงดีดแนวตั้งเพิ่มขึ้น</li></ul><h3>เฉพาะคอนโซล</h3><ul><li>Spectre: ระยะเวลาเบี่ยงทิศทางเพิ่ม 0.20 → 0.28 วินาที</li><li>Stinger: แรงดีดแนวตั้งเพิ่มขึ้น</li><li>Bulldog: ระยะเวลาเบี่ยงทิศทางเพิ่ม 0.50 → 0.60 วินาที</li><li>Phantom: ระยะเวลาเบี่ยงทิศทาง 0.50 → 0.6 วินาที, จำนวนกระสุนไม่เบี่ยงเพิ่ม 5 → 8 นัด</li><li>Vandal: ระยะเวลาเบี่ยงทิศทาง 0.50 → 0.6 วินาที, จำนวนกระสุนไม่เบี่ยงเพิ่ม 5 → 6 นัด</li></ul><h2>อัปเดตโหมด COMPETITIVE</h2><p>ตั้งแต่แพตช์ 11.09 บัญชีที่แชร์กันเล่นต้องเปิดใช้งานการยืนยันตัวตนหลายขั้นตอน (MFA) ด้วย Riot Mobile เพื่อเข้าคิว Competitive</p><p>โหมดอื่น ๆ ไม่ได้รับผลกระทบ</p><h2>อัปเดตระบบเกมเพลย์</h2><p>ปรับปรุงการแสดงตัวอย่างสกิลบนแผนที่ให้แม่นยำมากขึ้น เช่น Spycam ของ Cypher และ Sound Sensor ของ Deadlock</p><ul><li>ตัวอย่างสกิลตรงกับตำแหน่งจริงมากขึ้น</li><li>Sound Sensor ของ Deadlock แสดงตัวอย่างราบรื่นขึ้น ไม่กระโดดหรือเคลื่อนไหวฉับไว</li></ul><h2>อัปเดตพฤติกรรมผู้เล่น</h2><ul><li>เพิ่มหมวด “การบิดเบือนแรงค์” สำหรับรายงานผู้เล่นที่ใช้ระบบจับคู่แข่งขันในทางที่ผิด เช่น สเมิร์ฟ, การผลัดกันชนะ, การปั๊มแรงค์</li></ul><h2>อัปเดต PREMIER</h2><h3>Stage V25A6</h3><ul><li>16 ทีมแรกใน Invite จะได้อยู่ใน Invite ต่อ</li><li>ทีมอื่น ๆ ใน Invite จะถูกลดชั้นเมื่อเริ่ม Stage ถัดไป</li><li>ดิวิชั่นอื่นนอก Invite จะไม่มีการลดชั้น แต่ยังคงเลื่อนชั้นตามปกติ</li></ul><h3>สิทธิ์อยู่ในดิวิชั่น Contender</h3><ul><li>สิทธิ์ปี 2025 สิ้นสุด Stage V25A6</li><li>ปี 2026 ต้องผ่านเกณฑ์คัดเลือก Stage V25A6 หรือช่วงเวลาที่กำหนด</li><li>เกณฑ์: เล่นแมตช์ประจำสัปดาห์/Playoff, แรงค์ Immortal 3+, หรือเล่นแมตช์ Playoff ใน Elite 5</li></ul><h3>แท็กทีม VCT</h3><ul><li>ขยายฟีเจอร์แท็กทีมให้มีแท็กทีม VCT</li><li>แสดงแท็กในทุกส่วนของไคลเอนต์ เช่น แผงโซเชียล, ล็อบบี้, เกม, กระดานอันดับ</li><li>ชื่อและแท็กทีมสงวนให้ทีมพันธมิตร VCT</li><li>ทีม Premier ที่ใช้ชื่อ/แท็กเหมือน VCT จะได้รับแจ้งเตือนให้เปลี่ยนชื่อทีม</li></ul>
','https://cmsassets.rgpub.io/sanity/images/dsfx7636/news_live/2731bc4ccbb4617d3a26b3597c276f8735edeca3-1920x1080.jpg?auto=format&fit=fill&q=80&w=1184', 'อัปเดตเกม',now() - interval '4 day' ),
('สิ้นสุดการรอคอย-seven-knights-re-birth-เปิดตัวอย่างเป็นทางการ','สิ้นสุดการรอคอย-seven-knights-re-birth-เปิดตัวอย่างเป็นทางการ.','<p class="subtitle">ฉลองยิ่งใหญ่ด้วยกิจกรรมสุดพิเศษมากมาย ห้ามพลาด เล่นเลย !!</p><p class="meta">กรุงเทพฯ, ประเทศไทย (วันที่ 18 กันยายน พ.ศ. 2568)</p><p>เน็ตมาร์เบิ้ล ผู้พัฒนาและผู้เผยแพร่เกมคุณภาพสูงชั้นนำ ได้เปิดตัวเกม Collectible RPG ใหม่ล่าสุดอย่าง <strong>Seven Knights Re:BIRTH</strong> อย่างเป็นทางการทั้งบนแพลตฟอร์มมือถือและพีซีแล้วทั่วโลก ผู้เล่นสามารถดาวน์โหลดเกมได้แล้วผ่าน Google Play และ App Store สำหรับเวอร์ชันมือถือ และเว็บไซต์แบรนด์ทางการสำหรับเวอร์ชัน PC</p><p>เกมเปิดตัวแล้ว! ผู้เล่น <strong>Seven Knights Re:BIRTH</strong> สามารถสะสมและฝึกฝนอัศวินได้กว่า 120 ตัวละคร พร้อมสัตว์เลี้ยงกว่า 30 ตัว นอกจากนี้ยังสามารถเพลิดเพลินไปกับหลากหลายคอนเทนต์นอกเหนือจากโหมดผจญภัย เช่น อารีน่า, สงครามกิลด์, เรด, และอื่น ๆ อีกมากมาย</p><img src="https://sgimage.netmarble.com/images/netmarble/tskgb/20250521/f1xd1747818326238.jpg"><h2>กิจกรรมฉลองเปิดตัวสุดพิเศษ</h2><ul><li><strong>กิจกรรมเช็กชื่อรายวัน:</strong> มอบรางวัลผู้เล่นด้วยไอเทมภายในเกมสุดคุ้ม เช่น ทอง, กล่องกุญแจ, รูบี้, และอีกมากมาย อีกทั้งยังรับประกันว่าจะได้รับหนึ่งอัศวินตำนานทุก ๆ 10 วันหลังเช็กชื่อ</li><li><strong>กิจกรรมบัฟนักผจญภัยหน้าใหม่ & เช็กชื่อ:</strong> มีการมอบบัฟให้ผู้เล่นใหม่เพื่อช่วยเพิ่มอัตราการดรอปของอัศวิน, ทอง, และอุปกรณ์ต่าง ๆ เมื่อเล่นโหมดผจญภัย พร้อมกิจกรรมเช็กชื่อนักผจญภัยหน้าใหม่ที่มอบตั๋ว, วัตถุดิบวิวัฒนาการ, ทอง, และอีกมากมาย</li><li><strong>กิจกรรมเรียกพิกอัป:</strong> ผู้เล่นหน้าใหม่สามารถเข้าร่วมกิจกรรมเรียกพิกอัปในเวลาจำกัดได้ โดยนำเสนออัศวินตำนาน “แทโอ”</li></ul><p>นอกจากนี้ยังมีกิจกรรมเปิดตัวเพิ่มเติมอีกมากมาย สามารถติดตามรายละเอียดอย่างครบถ้วนได้บนฟอรัมทางการของเกม</p><h2>ตำนานแห่ง Seven Knights กลับมาอีกครั้ง</h2><p><strong>‘เซเว่นไนท์’ (Seven Knights)</strong> คือ IP เรือธงของเน็ตมาร์เบิ้ลที่มียอดดาวน์โหลดทั่วโลกทะลุ 100 ล้านครั้ง และได้รับความรักจากแฟน ๆ ทั่วโลก เกมต้นฉบับเปิดตัวในเดือนตุลาคม 2015 และได้รับการยกย่องในด้านงานภาพอันสวยงามตระการตา, ระบบการเล่นเชิงกลยุทธ์, และความสนุกสนานจากการสะสมตัวละครกว่า 500 ตัว</p><p><strong>Seven Knights Re:BIRTH</strong> สานต่อองค์ประกอบสำคัญจากเกมต้นฉบับ เช่น เนื้อเรื่อง, ตัวละคร, ระบบการต่อสู้ และกลไกหลัก พร้อมยกระดับประสบการณ์ด้วยฟีเจอร์เกมเพลย์ที่ทันสมัย ตัวเกมเปิดตัวในเกาหลีเมื่อวันที่ 15 พฤษภาคม 2568 และขึ้นสู่อันดับหนึ่งบนชาร์ต “เกมฟรียอดนิยม” ของ App Store (เกาหลี) ภายในเวลาเพียง 7 ชั่วโมง อีกทั้งยังติดอันดับหนึ่งใน “เกมที่ทำรายได้ยอดนิยม” ทั้งบน Google Play และ App Store ในเกาหลีภายในเวลาเพียง 5 วันหลังจากเปิดตัวอีกด้วย</p><p>สามารถติดตามรายละเอียดเพิ่มเติมเกี่ยวกับ <strong>Seven Knights Re:BIRTH</strong> ได้ที่เว็บไซต์ทางการและฟอรั่มของเกม แฟน ๆ ยังสามารถติดตามข่าวสารล่าสุดได้ที่ช่องทางโซเชียลมีเดียอย่าง Facebook และ YouTube</p>
','https://thisisgamethailand.com/wp-content/uploads/2025/09/Seven-Knights-ReBIRTH_main-3.jpg','เกมมือถือ',now() - interval '4 week'),
('Silenthillf','สิ้นสุดการรอคอย!! เกม Silent Hill f กับที่สุดของเกมหลอนสุดสยองขวัญแห่งปี เปิดตัววางจำหน่ายแล้ววันนี้!!','<style>h1.title,h2{text-align:left;margin-bottom:0.5em;}p.subtitle,p.lead,p.note{text-align:left;}table{width:100%;border-collapse:collapse;margin-bottom:1.2em;}th,td{text-align:left;padding:8px 12px;border-bottom:1px solid rgba(255,255,255,0.1);}th{width:35%;color:#ffd;font-weight:bold;}</style><h1 class="title">Silent Hill f — บทใหม่ของแฟรนไชส์สยองขวัญในตำนาน</h1><p class="subtitle">ย้ายฉากไปยังชนบทญี่ปุ่นยุค 1960s กับเรื่องราวของเด็กสาวผู้ต้องเอาตัวรอดจากความวิบัติของ “ดอกลิลลี่สีแดง”</p><p><strong>Silent Hill f</strong> คือบทใหม่ของแฟรนไชส์สยองขวัญในตำนาน ที่ย้ายฉากไปยังชนบทญี่ปุ่นยุค 1960s เล่าเรื่องของ “<strong>ชิมิซุ ฮินาโกะ</strong>” เด็กสาวมัธยมที่ต้องเอาตัวรอดจากเมืองเอบิสึกะโอกะ ซึ่งกำลังผุพังและวิบัติด้วย “ดอกลิลลี่สีแดง” และสิ่งลี้ลับเหนือคำอธิบาย</p><p>เกมโดดเด่นทั้งงานเขียนที่ทรงพลัง บรรยากาศที่หลอนจับใจ และกิมมิกระบบ <strong>“ศรัทธา (Faith)”</strong> / <strong>“โอมาโมริ (Omamori)”</strong> ที่ช่วยอัปเกรดความสามารถถาวรของผู้เล่น รวมถึงระบบการต่อสู้ประชิดที่ต้องอาศัยจังหวะในการหลบและพารรี่ เพื่อเอาชนะเหล่าสิ่งมีชีวิตประหลาดที่แฝงอยู่ในหมู่บ้าน</p><p>แม้จะมีช่วงจังหวะที่ยืดและพื้นที่บางส่วนคับแคบจนควบคุมได้ยากอยู่บ้าง แต่โดยรวมแล้ว <strong>Silent Hill f</strong> ถือเป็น “วิวัฒนาการ” ที่ทั้งสวย หลอน และคมคายอย่างยิ่งของซีรีส์ในตำนานนี้</p><h1 class="title">สเปค PC สำหรับเล่น Silent Hill f</h1><p class="lead">ทาง Konami และ NeoBards Entertainment Ltd. เปิดเผยสเปค PC สำหรับ Silent Hill f — เกมสยองขวัญเอาตัวรอดที่ย้ายฉากไปยังญี่ปุ่นยุค 1960s</p><section aria-labelledby="minimum-specs"><h2 id="minimum-specs">ขั้นต่ำ</h2><p>ต้องการโปรเซสเซอร์และระบบปฏิบัติการแบบ 64 บิต</p><table><tbody><tr><th>ระบบปฏิบัติการ</th><td>Windows 11 x64</td></tr><tr><th>โปรเซสเซอร์</th><td>Intel Core i5-8400 / AMD Ryzen 5 2600</td></tr><tr><th>หน่วยความจำ</th><td>แรม 16 GB</td></tr><tr><th>กราฟิกส์</th><td>NVIDIA® GeForce® GTX 1070 Ti / AMD Radeon™ RX 5700</td></tr><tr><th>DirectX</th><td>เวอร์ชัน 12</td></tr><tr><th>พื้นที่จัดเก็บข้อมูล</th><td>พื้นที่ว่างที่พร้อมใช้งาน 50 GB</td></tr><tr><th>การ์ดเสียง</th><td>Windows Compatible Audio Device</td></tr></tbody></table><p class="note"><strong>หมายเหตุเพิ่มเติม:</strong> การเล่นบนสเปคขั้นต่ำควรเล่นได้ที่คุณภาพแบบ Performance ที่ 30 FPS ที่ความละเอียด 720p. ข้อแนะนำให้ใช้ SSD.</p></section><section aria-labelledby="recommended-specs"><h2 id="recommended-specs">ขั้นแนะนำ</h2><p>ต้องการโปรเซสเซอร์และระบบปฏิบัติการแบบ 64 บิต</p><table><tbody><tr><th>ระบบปฏิบัติการ</th><td>Windows 11 x64</td></tr><tr><th>โปรเซสเซอร์</th><td>Intel Core i7-9700 / AMD Ryzen 5 5500</td></tr><tr><th>หน่วยความจำ</th><td>แรม 16 GB</td></tr><tr><th>กราฟิกส์</th><td>NVIDIA® GeForce® RTX 2080 / AMD Radeon™ RX 6800 XT</td></tr><tr><th>DirectX</th><td>เวอร์ชัน 12</td></tr><tr><th>พื้นที่จัดเก็บข้อมูล</th><td>พื้นที่ว่างที่พร้อมใช้งาน 50 GB</td></tr><tr><th>การ์ดเสียง</th><td>Windows Compatible Audio Device</td></tr></tbody></table><p class="note"><strong>หมายเหตุเพิ่มเติม:</strong> การเล่นบนสเปคแนะนำควรทำให้เล่นได้ที่ Performance 60 FPS หรือ Quality 30 FPS ที่ความละเอียด Full HD (หรือ 4K โดยใช้เทคโนโลยีอย่าง DLSS หรือเทคโนโลยีที่คล้ายกัน). ต้องใช้ SSD.</p></section>
','https://thisisgamethailand.com/wp-content/uploads/2025/09/SILENT-HILL-f_main.jpg','เกมใหม่',now() - interval '3 week'),
('battlefield6','Battlefield™ 6 ภาคใหม่มาแล้ว!!!','<style>h1.title,h2{text-align:left;margin-bottom:0.5em}p.lead{text-align:left;margin-bottom:1em}table{width:100%;border-collapse:collapse;margin-bottom:1.5em}table th,table td{text-align:left;padding:8px 12px;border-bottom:1px solid rgba(255,255,255,0.1)}table th{width:35%;font-weight:bold;color:#ffd}section{margin-top:1.5em}</style><p>สุดยอดประสบการณ์การทําสงครามเต็มรูปแบบ ต่อสู้ในการรบที่ดุเดือดของทหารราบ ทะยานสู่ท้องฟ้าเพื่อต่อสู้กลางเวหา ทําลายสภาพแวดล้อมของคุณเพื่อสร้างความได้เปรียบทางยุทธศาสตร์ ควบคุมทุกการกระทำและการเคลื่อนไหวได้อย่างสมบูรณ์โดยใช้ Kinesthetic Combat System ในสงครามที่เต็มไปด้วยรถถัง เครื่องบินรบ และยุทโธปกรณ์ขนาดมหึมา อาวุธที่อันตรายที่สุดก็คือหน่วยรบของคุณ นี่คือ Battlefield 6</p><img src="https://images-wixmp-ed30a86b8c4ca887773594c2.wixmp.com/f/af7dfb2d-8cc1-45ab-9bab-6b0d0c655e58/dk9d2c5-cb55feff-1229-4c9b-9e2e-f5ba7eb4f47d.jpg?token=eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..plq2t0mdWGVmsF73ik343BOd3k6QocljJVnmazyKpSE"><h1 class="title">สเปค PC สำหรับเล่นเกม</h1><p class="lead">สเปคที่แนะนำโดยผู้พัฒนา สำหรับการเล่นเกมในระดับต่าง ๆ ทั้งขั้นต่ำและขั้นแนะนำ</p><section aria-labelledby="minimum-specs"><h2 id="minimum-specs">ขั้นต่ำ: <span>1080p 30 FPS Low Settings</span></h2><p>ต้องการโปรเซสเซอร์และระบบปฏิบัติการแบบ 64 บิต</p><table><tbody><tr><th>ระบบปฏิบัติการ</th><td>Windows 10</td></tr><tr><th>โปรเซสเซอร์</th><td>Intel Core i5-8400 / AMD Ryzen 5 2600</td></tr><tr><th>หน่วยความจำ</th><td>แรม 16 GB</td></tr><tr><th>กราฟิกส์</th><td>Nvidia RTX 2060 / AMD Radeon RX 5600 XT 6GB</td></tr><tr><th>DirectX</th><td>เวอร์ชัน 12</td></tr><tr><th>เครือข่าย</th><td>การเชื่อมต่ออินเทอร์เน็ตแบบบรอดแบนด์</td></tr><tr><th>พื้นที่จัดเก็บข้อมูล</th><td>พื้นที่ว่างที่พร้อมใช้งาน 55 GB</td></tr><tr><th>การ์ดเสียง</th><td>No Recommendation</td></tr><tr><th>การรองรับ VR</th><td>Not Supported</td></tr></tbody></table></section><section aria-labelledby="recommended-specs"><h2 id="recommended-specs">ขั้นแนะนำ: <span>1080p 80 FPS+ Low Settings / 1440p 60 FPS High Settings</span></h2><p>ต้องการโปรเซสเซอร์และระบบปฏิบัติการแบบ 64 บิต</p><table><tbody><tr><th>ระบบปฏิบัติการ</th><td>Windows 11</td></tr><tr><th>โปรเซสเซอร์</th><td>Intel Core i7-10700 / AMD Ryzen 7 3700X</td></tr><tr><th>หน่วยความจำ</th><td>แรม 16 GB</td></tr><tr><th>กราฟิกส์</th><td>Nvidia RTX 3060 Ti / AMD Radeon RX 6700 XT</td></tr><tr><th>DirectX</th><td>เวอร์ชัน 12</td></tr><tr><th>เครือข่าย</th><td>การเชื่อมต่ออินเทอร์เน็ตแบบบรอดแบนด์</td></tr><tr><th>พื้นที่จัดเก็บข้อมูล</th><td>พื้นที่ว่างที่พร้อมใช้งาน 80 GB</td></tr><tr><th>การ์ดเสียง</th><td>No Recommendation</td></tr><tr><th>การรองรับ VR</th><td>Not Supported</td></tr></tbody></table></section>
','https://shared.fastly.steamstatic.com/store_item_assets/steam/apps/2807960/a9052c33c3bc80dc8f55fbfb3d18a62d6d762b2a/capsule_616x353.jpg?t=1760108538','เกมใหม่',now() - interval '1 week'),
('gta6','GTA 6 เปิดโลกใหม่กับเนื้อเรื่องสุดเข้มข้น พร้อมวันวางจำหน่ายอย่างเป็นทางการ !','<style>body{font-family:"Sarabun",sans-serif;background-color:#0a0f1a;color:#e9eef5;line-height:1.7;margin:2rem auto;max-width:900px;padding:0 1.5rem;}h1,h2,h3{color:#D3D3D3;text-align:left;margin-bottom:0.5em;}p{text-align:justify;margin-bottom:1em;}table{width:100%;border-collapse:collapse;margin-top:1em;margin-bottom:1.5em;background:rgba(255,255,255,0.03);border-radius:8px;overflow:hidden;}th,td{text-align:left;padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.1);}th{width:35%;color:#ffd;}tr:last-child td{border-bottom:none;}strong{color:#FFFFE0;}</style></head><body><h1>GTA 6 (Grand Theft Auto VI)</h1><p>เรียกได้ว่าเป็นเกมที่แฟน ๆ ทั่วโลกรอคอยมากที่สุดในรอบทศวรรษสำหรับ <strong>GTA 6 (Grand Theft Auto VI)</strong> หลังจากภาค 5 ที่วางจำหน่ายบน PS3, Xbox 360 ตั้งแต่ปี 2013 ล่าสุดทาง <strong>Rockstar Games</strong> ผู้พัฒนาเกมซีรีส์ Grand Theft Auto ก็ได้เปิดตัวเกมภาคล่าสุดพร้อมประกาศวันวางจำหน่ายอย่างเป็นทางการออกมาแล้ว สำหรับใครที่กำลังตั้งหน้าตั้งตารอคอยที่จะได้เล่นเกมนี้อยู่ รวมถึงผู้ที่อาจจะยังไม่ค่อยรู้ว่าเป็นเกมแนวไหน น่าสนใจยังไง วันนี้เรารวบรวมข้อมูลมาฝากเพื่อน ๆ กันแล้ว</p><h2>GTA 6 คือเกมอะไร แนวไหน</h2><p><strong>GTA 6</strong> เป็นเกมแนว <em>Open World Action-Adventure</em> ที่ผสมผสานระหว่างการดำเนินเนื้อเรื่องเชิงภาพยนตร์กับโลกอิสระแบบ Sandbox ซึ่งผู้เล่นสามารถเดินทาง ขับรถ ต่อสู้ หรือใช้ชีวิตในเมืองได้อย่างอิสระ ซึ่งนี่คือจุดแข็งที่ทำให้ซีรีส์ GTA ได้รับความนิยมมาอย่างยาวนาน</p><p>ภาคนี้จะพาผู้เล่นกลับสู่เมือง <strong>Vice City</strong> และพื้นที่รอบรัฐ <strong>Leonida</strong> ที่ได้รับแรงบันดาลใจจากรัฐฟลอริดา โดยมีตัวละครหลักคือ <strong>Jason</strong> และ <strong>Lucia</strong> คู่หูที่ต้องเอาตัวรอดในโลกอาชญากรรม ผ่านภารกิจที่เข้มข้นและเต็มไปด้วยดราม่า พร้อมระบบเกมที่มีการพัฒนาให้ล้ำหน้ากว่าทุกภาคที่ผ่านมา รวมถึงโลกในเกมที่ใหญ่และสมจริงมากยิ่งขึ้น</p><img src="https://s359.thaicdn.net//pagebuilder/bd8a015f-d86c-4fcf-b8df-b932a521d280.jpg"><h2>GTA 6 มาเมื่อไหร่</h2><p><strong>Rockstar Games</strong> ได้ประกาศอย่างเป็นทางการว่า <strong>GTA 6</strong> มีกำหนดวางจำหน่ายในวันที่ <strong>26 พฤษภาคม 2026</strong> สำหรับแพลตฟอร์ม <strong>PlayStation 5</strong> และ <strong>Xbox Series X|S</strong> โดยมีการเลื่อนให้ล่าช้ากว่ากำหนดเดิมในช่วงปี 2025 เนื่องจากต้องการเวลาเพิ่มเติมในการพัฒนาเพื่อให้ได้คุณภาพตามที่แฟน ๆ คาดหวัง</p><p>ส่วนเวอร์ชั่น PC ยังไม่มีการยืนยันวันวางจำหน่ายอย่างชัดเจน ซึ่งอาจหมายความว่าแฟนเกม PC ต้องอดใจรอกันอีกระยะหนึ่งหลังจากที่วางจำหน่ายบนคอนโซลไปแล้ว</p><img src="https://s359.thaicdn.net//pagebuilder/549aa9c7-d42c-4194-a5f3-1ee1186cacce.jpg"><h2>GTA 6 ราคาเท่าไร</h2><p>ในขณะนี้ <strong>Rockstar Games</strong> ยังไม่ได้เปิดเผยราคาอย่างเป็นทางการของ <strong>GTA 6</strong> แต่จากแนวโน้มในด้านราคาของเกมระดับ AAA ในยุคปัจจุบัน มีความเป็นไปได้ว่า GTA 6 จะมีราคาเริ่มต้นอยู่ที่ประมาณ <strong>$69.99 (ราว 2,300 บาท)</strong> สำหรับเวอร์ชั่นมาตรฐาน และอาจมีเวอร์ชั่นพิเศษ เช่น <em>Deluxe Edition</em> หรือ <em>Collector’s Edition</em> ที่มีราคาสูงกว่านี้ โดยมาพร้อมของแถมพิเศษหรือเนื้อหาเสริม (DLC)</p><h2>GTA 6 สเปกขั้นต่ำที่ต้องการ (คาดการณ์)</h2><p>ณ ตอนนี้ยังไม่มีการประกาศสเปกขั้นต่ำอย่างเป็นทางการสำหรับ <strong>GTA 6</strong> บน PC เนื่องจากตัวเกมยังไม่ได้ยืนยันวันวางจำหน่ายบนแพลตฟอร์มนี้ อย่างไรก็ตาม หากพิจารณาจากกราฟิกในเทรลเลอร์และประสิทธิภาพของเครื่องคอนโซลในยุคปัจจุบัน คาดการณ์ว่าสเปกขั้นต่ำอาจอยู่ในระดับประมาณนี้:</p><table><tbody><tr><th>ระบบปฏิบัติการ (OS)</th><td>Windows 10 64-bit</td></tr><tr><th>หน่วยประมวลผล (CPU)</th><td>Intel Core i7-8700 / AMD Ryzen 5 3600</td></tr><tr><th>หน่วยความจำ (RAM)</th><td>16 GB</td></tr><tr><th>กราฟิกการ์ด (GPU)</th><td>NVIDIA GeForce GTX 1660 Super / AMD Radeon RX 5600 XT</td></tr><tr><th>พื้นที่จัดเก็บข้อมูล (Storage)</th><td>SSD 150 GB ขึ้นไป</td></tr><tr><th>DirectX</th><td>Version 12</td></tr></tbody></table><img src="https://s359.thaicdn.net//pagebuilder/40e66846-58fa-4cd8-9ee3-61be9d4a707e.jpg"><p><strong>หมายเหตุ:</strong> สเปกเหล่านี้เป็นเพียงการคาดการณ์จากนักวิเคราะห์และแฟนเกมเท่านั้น ยังไม่ใช่ข้อมูลที่ Rockstar ยืนยันอย่างเป็นทางการ</p><h3>สรุป</h3><p>ถึงแม้ว่าปัจจุบันทาง <strong>Rockstar Games</strong> จะยังไม่ได้เปิดเผยรายละเอียดของเกม <strong>GTA 6</strong> ออกมามากนัก แต่จากภาพและเทรลเลอร์ที่ปล่อยออกมาก็ทำให้แฟน ๆ ทั่วโลกรู้สึกตื่นเต้นและนับวันรอที่จะได้สัมผัสประสบการณ์ใหม่ในเมือง Vice City อีกครั้งกันแล้ว</p></body>
','https://300mind.studio/blog/wp-content/uploads/2023/12/GTA-6-Game.webp','ข่าวเกม',now() - interval '2 month'),
('kaijuno8','Kaiju No.8 The Game เปิดให้เล่นฟรีแล้วทั่วโลก ทั้งในระบบ iOS และ Android','<section class="article"><h2 style="color: #8b5cf6; text-align: left;">Kaiju No.8 The Game เปิดให้บริการทั่วโลกแล้ว!</h2><p>อีกหนึ่งเกมมือถือใหม่ชวนเล่น <strong>Kaiju No.8 The Game</strong> เกมแนว Turn-based Battle RPG ที่สร้างจากมังงะและอนิเมะยอดนิยม ได้เปิดให้บริการทั่วโลกอย่างเป็นทางการแล้วตั้งแต่วันที่ <strong>31 สิงหาคมที่ผ่านมา</strong> หลังจากมียอดผู้ลงทะเบียนทะลุหนึ่งล้านคน!</p><p>เกมนี้มาในรูปแบบ <strong>Turn-based RPG</strong> ที่มีระบบการต่อสู้สุดมันส์ สวมบทบาทเป็นกองกำลังป้องกันเพื่อต่อสู้กับเหล่าไคจู พร้อมเนื้อเรื่องจัดเต็มถึง <strong>3 แบบ</strong> ได้แก่ <strong>เนื้อเรื่องหลัก</strong> ที่สานต่อจากซีรีส์, <strong>โหมดความทรงจำ</strong>, และ <strong>โหมดเรื่องราวของตัวละคร</strong> โดยทุกเนื้อเรื่องมาพร้อมกับ <strong>เสียงพากย์เต็มรูปแบบ</strong> เพื่อเพิ่มอรรถรสในการเล่นให้สนุกและอินมากยิ่งขึ้น</p><img src="https://www.gamemonday.com/wp-content/uploads/2025/09/Kaiju-No.8-The-Game-010925-02-1024x576.jpg"><p>และไม่ควรพลาด! หากเข้าเล่นเกมในช่วงนี้ ผู้เล่นสามารถเลือกรับ <strong>ตัวละครระดับ 5 ดาวฟรี</strong> ได้ทันที ไม่ว่าจะเป็น <strong>ริน ชิโนโนเมะ</strong>, <strong>เก็น นารุมิ</strong>, หรือ <strong>คิโครุ ชิโนมิยะ</strong> และอีกมากมาย!</p><p>โหลดมาเล่นได้แล้ววันนี้ทั้งบน App Store และ Google Play แฟนอนิเมะ <strong>ไคจูหมายเลข 8</strong> ไม่ควรพลาดเกมนี้เลย!</p><img src="https://www.gamemonday.com/wp-content/uploads/2025/09/Kaiju-No.8-The-Game-010925-03-1024x576.jpg"></section>
','https://thisisgamethailand.com/wp-content/uploads/2025/04/700M-Kaiju-No.-8-THE-GAME-Pre-Reg-Start.jpg','เกมมือถือ',now() - interval '1 month'),
('ghostyotei','สิ้นสุดการรอคอย!! เกม Ghost of Yotei ที่สุดแห่งเกมแอ็คชั่นซามูไรแบบโอเพ่นเวิร์ลแห่งยุคที่ทุกคนรอคอย','<h1>Ghost of Yōtei</h1><p>เกม <strong>Ghost of Yōtei</strong> ดำเนินเรื่องราวในชนบทของญี่ปุ่นในยุค 1600 ซึ่งเกิดขึ้น 300 ปีให้หลังจากเกมที่ได้รับคำชมอย่างล้นหลามอย่าง Ghost of Tsushimaพร้อมออกติดตาม <strong>Atsu</strong> นักรบหญิงผู้โดดเดี่ยวที่ถูกหลอกหลอนด้วยความกระหายในการแก้แค้น</p><p>ธอเดินทางผ่านดินแดนเอโซะ ภูมิประเทศที่งดงามแต่ก็อันตรายของญี่ปุ่นตอนเหนือ เพื่อออกตามล่าผู้ที่สังหารครอบครัวของเธอเมื่อหลายปีก่อน!</p><p>สัมผัสความมันส์และบ้าพลังไปกับนักรบปีศาจแห่งโยเทได้แล้วตอนนี้ กับเกม <strong>Ghost of Yōtei</strong> บน <strong>PS5</strong> และ <strong>PS5 Pro</strong> เท่านั้น!! ตัวเกมรองรับซับและเมนูภาษาไทยแบบเต็มรูปแบบ!!</p><img src="https://static0.gamerantimages.com/wordpress/wp-content/uploads/wm/2025/09/ghost-of-yotei-director-addresses-jin-sakai-fan-theory-game-rant-feature.jpg?w=1600&h=900&fit=crop">','https://image.api.playstation.com/vulcan/ap/rnd/202504/2116/49934c62a922417e86bd3fc61a59b116cf7ae51e91d9a9de.jpg','เกมใหม่',now() - interval ' 3 week'),
('marvelnewmode','Marvel Rivals เปิดตัวโหมดซอมบี้ใหม่ล่าสุดและกิจกรรมพิเศษฮาโลวีน','<article><h1>Marvel Rivals เปิดตัวโหมด PvE Zombie ใหม่!</h1><p class="date">กรุงเทพฯ ประเทศไทย – 17 ตุลาคม 2568</p><p>วันนี้ที่งาน <strong>gamescom Asia</strong> และงาน <strong>Thailand Game Show</strong> ทาง <strong>Marvel Games</strong> และ <strong>NetEase Games</strong> ได้เปิดเผยรายละเอียดและประกาศใหม่ๆ ของเกม <strong>Marvel Rivals</strong> เกมยิงปืนซูเปอร์ฮีโร่แบบทีม PVP ที่ได้รับรางวัลและคำชมเชยมากมาย</p><p>เกมนี้จะให้ผู้เล่นได้รวมทีมซูเปอร์ฮีโร่และเหล่าวายร้ายที่พัฒนาอย่างต่อเนื่อง ต่อสู้ด้วยพลังพิเศษในแผนที่หลากหลายที่สามารถทำลายได้จากทั่วทั้งจักรวาล <em>Marvel Multiverse</em> และมาพร้อมกับโหมด <strong>PvE Zombie</strong> ใหม่ล่าสุดแบบจำกัดเวลา!</p><div class="highlight">การประกาศครั้งนี้ได้รับเกียรติจาก <strong>Danny Koo</strong> ผู้อำนวยการสร้างของ Marvel Games ในระหว่างการนำเสนอหลักของทั้งสองงาน</div><p>ภายใต้การนำของ <strong>คอนชู</strong> บุกมิดทาวน์นิวยอร์กที่กำลังถูกไวรัสซอมบี้กลืนกิน ร่วมกับเพื่อนร่วมทีมซูเปอร์ฮีโร่ที่เหลืออยู่ ภารกิจของคุณคือหนึ่งเดียว: <strong>ค้นหาและหยุดยั้งราชินีแห่งความตายและแผนการร้ายของเธอ</strong> ไม่ว่าจะต้องแลกด้วยอะไรก็ตาม!</p><p>โหมดใหม่นี้ได้รับแรงบันดาลใจจาก <em>Marvel Zombies</em> ของ <strong>Marvel Animation</strong> โดยผู้เล่นจะได้สวมบทบาทเป็น <strong>ธอร์</strong>, <strong>เบลด</strong>, <strong>แมจิก</strong>, <strong>เจฟฟ์</strong> หรือ <strong>เดอะพันนิชเชอร์</strong> เพื่อรับมือกับฝูงซอมบี้ที่หลั่งไหลมาไม่สิ้นสุด!</p><p>คุณจะต้องเอาชีวิตรอดจากฝูงซอมบี้ ประจันหน้ากับ <strong>ซอมบี้นามอร์</strong> และ <strong>ราชินีแห่งความตาย</strong> ในฐานะบอสสุดโหด พร้อมต่อสู้เพื่อปกป้องโลกจากการถูกซอมบี้กลืนกิน!</p><h2>ความสามารถพิเศษของเหล่าฮีโร่</h2><ul><li><strong>เจฟฟ์</strong> – บุกทะลวงฝูงซอมบี้อย่างบ้าคลั่ง</li><li><strong>เบลด</strong> – ฟันฝ่าด้วยดาบจันทร์ที่กระเด้งไปมา</li><li><strong>ธอร์</strong> – ช็อตซอมบี้ด้วยพลังสายฟ้าในสถานะ <em>Awakening</em></li><li><strong>แมจิก</strong> – ปลดปล่อยพลังร่าง <em>Darkchild</em> ไร้ขีดจำกัด</li></ul><div class="highlight">โชว์ฝีมือการต่อสู้สุดอลังการของคุณในโหมด PvE Zombie สุดมันส์ของ <strong>Marvel Rivals</strong> ได้แล้ววันนี้!</div></article>
','https://www.mustplay.in.th/static/thumb/2025/9/18/attach-1760725068496.jpg','อัปเดตเกม',now() - interval '2 day'),
('solooverdrive','Solo Leveling: ARISE OVERDRIVE เผยรายละเอียดใหม่!!','<article><h1>Solo Leveling: ARISE OVERDRIVE เตรียมเปิดตัวทั่วโลก 17 พฤศจิกายนนี้!</h1><p class="date">กรุงเทพฯ ประเทศไทย – ตุลาคม 2568</p><p><strong>Solo Leveling: ARISE OVERDRIVE</strong> เตรียมเปิดตัวพร้อมกันทั่วโลกในวันที่ <strong>17 พฤศจิกายนนี้</strong> ผ่านทาง <strong>Steam</strong> และ <strong>Xbox PC</strong>!</p><p>ตัวเกมกำลังเข้าร่วมงาน <strong>TwitchCon San Diego 2025</strong> ซึ่งจัดขึ้นระหว่างวันที่ 17 - 19 ตุลาคม ณ <em>San Diego Convention Center</em> โดยเปิดโอกาสให้ผู้เข้าร่วมงานได้สัมผัสประสบการณ์กับเดโมสุดพิเศษที่บูธเกม PC บูธ <strong>Solo Leveling: ARISE OVERDRIVE</strong> นอกจากนี้ ภายในงานยังมีการถ่ายทอดสดส่งตรงจากบูธผ่านช่องทาง Twitch ทางการของเกม โดยมีสตรีมเมอร์รับเชิญพิเศษมาร่วมเล่นเกมและแบ่งปันประสบการณ์จากมุมมองของพวกเขาอีกด้วย</p><p><strong>Solo Leveling: ARISE OVERDRIVE</strong> สร้างจากเว็บตูนยอดฮิตที่กลายเป็นปรากฏการณ์ระดับโลก ออกแบบมาสำหรับแพลตฟอร์ม PC และคอนโซล มาพร้อมกราฟิกคุณภาพสูงที่ชวนดื่มด่ำ กลไกการต่อสู้ชาญฉลาด และระบบพัฒนาตัวละครสุดล้ำลึก โดยผู้เล่นจะได้สวมบทบาทเป็น ‘<strong>ซองจินอู</strong>’ ในร่างจักรพรรดิ พร้อมร่วมต่อสู้แบบทีมสูงสุดสี่คนและเผชิญหน้ากับบอสสุดมันส์!</p><div class="highlight"><strong>Solo Leveling: ARISE OVERDRIVE</strong> เปิดสั่งซื้อล่วงหน้าแล้ววันนี้ โดยจะเปิดตัวทั่วโลกในวันที่ <strong>17 พฤศจิกายน</strong> บน Steam และ Xbox PC สำหรับผู้ที่สั่งซื้อล่วงหน้าแบบ <em>Deluxe Edition</em> จะได้รับสิทธิ์เข้าถึงเกมล่วงหน้า 3 วัน ตั้งแต่วันที่ <strong>14 พฤศจิกายน</strong> เป็นต้นไป!</div></article><img src="https://static0.thegamerimages.com/wordpress/wp-content/uploads/2025/10/ss_6dbcc3c2d96a9c121456de966f7e70e20170c8fe.jpg?w=1600&h=900&fit=crop"><img src="https://static0.thegamerimages.com/wordpress/wp-content/uploads/2025/10/ss_1b0a3b92d9e24ce0b27cbf446d38f888559f5d79.jpg?q=49&fit=crop&w=825&dpr=2"><img src="https://static0.gamerantimages.com/wordpress/wp-content/uploads/2025/06/sla-overdrive.jpg?q=49&fit=crop&w=825&dpr=2">
','https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2373990/076c85e9fccad9865b82d91e939f73a4a7314632/capsule_616x353.jpg?t=1756433976','เกมใหม่',now() - interval '1 day'),
('soulland','ถึงเวลาท่องยุทธภพ! Soul Land: Time Reversed เปิดให้บริการทั้งระบบ iOS และ Android สโตร์ไทยแล้ว!','<article><p>เหล่าวิญญาจารย์ทั้งหลาย ถึงเวลาท่องยุทธภพโต้วหลัวกันแล้ว! เพราะในตอนนี้ <strong>Soul Land: Time Reversed</strong> จาก moc games ได้เปิดให้เหล่าจอมยุทธ์เข้าไปผจญภัยกันแล้วทั้งระบบ iOS และ Android สโตร์ไทย เป็นเกมที่ขอบอกเลยว่า "งานอาร์ตสไตล์อนิเมะสวยมาก!" แถมเหล่าจอมยุทธ์ยังมาพร้อมระบบตัวละครสองสกินที่พร้อมจะพลิกสถานการณ์ในสนามรบให้กับเราอีกด้วยนะ เพื่อน ๆ ที่สนใจหรือกำลังรออยู่ สามารถดาวน์โหลดเกมไปสนุกกันได้เลย!</p><p><strong>Soul Land: Time Reversed</strong> เป็นเกมแนว Turn-based RPG ที่เราจะได้จัดทีมจอมยุทธ์จากซีรีส์จีนกำลังภายในสุดโด่งดัง “จอมยุทธ์ภูตถังซาน” เข้าพิชิตเหล่าศัตรูในดันเจี้ยนด้วยสกิลยุทธ์แสนทรงพลัง โดยจุดเด่นของเกมนี้คือ...</p><ul><li>งานภาพสองมิติสไตล์อนิเมะที่มีความสวยงามในทุกองค์ประกอบ</li><li>ภาพอิลลัสต์ประจำตัวจอมยุทธ์อันทรงเสน่ห์ที่มาพร้อมกลิ่นอายอนิเมะแบบจัดเต็ม</li><li>การต่อสู้สไตล์ออโต้ที่ถึงจะเรียบง่ายแต่ก็ต้องจัดทีมและวางตำแหน่งจอมยุทธ์ให้เหมาะสม</li><li>ระบบแปลงร่าง 2 สกินที่จะทำให้จอมยุทธ์ของเราเท่และแกร่งขึ้นได้ในระหว่างการต่อสู้</li><li>เรื่องราวมิติโต้วหลัวอันแสนบิดเบี้ยวที่เราจะต้องเข้าไปแก้ไขให้ถูกต้อง</li></ul><p>เป็นเกมมือถือจากจอมยุทธ์ภูตถังซานที่งานอาร์ตสวยงามมาก ๆ โดยเฉพาะภาพอิลลัสต์ของจอมยุทธ์นี่คืองานดีแบบขั้นสุดไปเลย ถ้าชอบภาพสไตล์อนิเมะบอกเลยว่าจะต้องถูกใจถังซานภาคนี้อย่างแน่นอน!</p></article>
','https://thisisgamethailand.com/wp-content/uploads/2025/09/Soul-Land-Time-Reversed-PR.jpg','เกมมือถือ',now() - interval '3 day'),
('lolwr','League of Legends: Wild Rift ฉลองครบรอบ 5 ปี ด้วยอัปเดตครั้งใหญ่!!','<article><p><strong>Wild Rift</strong> เตรียมเปิดฉากปาร์ตี้สุดยิ่งใหญ่ต้อนรับครบรอบ 5 ปี ด้วยคอนเทนต์จัดเต็ม ทั้งโหมดใหม่สุดมันส์ <strong>ARAM: Mayhem</strong>, การปรับปรุงระบบรูนครั้งใหญ่, อัปเดตสำหรับสายซัพพอร์ต, การปรับสมดุล Boot Enchantments และกิจกรรมฉลองครบรอบ พร้อมของรางวัลสุดพิเศษตลอดแพตช์!</p><h2>ARAM: Mayhem ปาร์ตี้สุดเดือดบนสะพานหิมะ</h2><p>โหมดใหม่ <strong>ARAM: Mayhem</strong> เตรียมระเบิดความสนุกด้วยระบบ <em>Augments</em> จาก Arena ที่ถูกนำมาผสมผสานเข้ากับรูปแบบ 5v5 ของ ARAM อย่างลงตัว ผู้เล่นสามารถเลือกเล่นได้ทั้ง ARAM ปกติ หรือ ARAM: Mayhem ผ่านคิวแยก และสามารถอ่านรายละเอียดเพิ่มเติมได้ใน Dev Blog ล่าสุดของทีมพัฒนา</p><p>ข่าวดีสำหรับแฟน ๆ ARAM เพราะแผนที่ยอดนิยมอย่าง <strong>Butcher’s Bridge</strong> และ <strong>Koeshin’s Crossing</strong> จะกลายเป็นแผนที่ถาวรในโหมด ARAM พร้อมการปรับปรุงประสิทธิภาพแผนที่อย่างต่อเนื่องเพื่อให้การเล่นลื่นไหลยิ่งขึ้น</p><h2>การอัปเดตรูนครั้งใหญ่ (Runes Revamp)</h2><p>หนึ่งในการอัปเดตหลักของแพตช์นี้คือการปรับระบบรูนใหม่ทั้งหมด เพื่อให้ผู้เล่นมีทางเลือกในการสร้างบิลด์ที่หลากหลายขึ้น และให้แชมเปี้ยนทุกตัวมีรูนที่เหมาะสมกับสไตล์การเล่นของตนมากขึ้น</p><h3>Keystone ใหม่: Dark Harvest</h3><p>รูนยอดฮิตจาก League PC กลับมาแล้ว! เมื่อสร้างความเสียหายให้แชมเปี้ยนที่มีพลังชีวิตต่ำกว่า 50% คุณจะเก็บ “วิญญาณ” ของพวกเขาเพื่อเพิ่มพลังโจมตีถาวร เหมาะกับสายล่าอย่าง <strong>Katarina</strong> หรือ <strong>Kha’Zix</strong></p><h3>รูนเสริมใหม่ทั้งหมด</h3><ul><li><strong>Celerity</strong>: แทนที่ Pathfinder เพิ่มโบนัสความเร็วเคลื่อนที่ทั้งหมด 7% และเพิ่มความเร็วอีก 2% เหมาะกับแชมเปี้ยนอย่าง Jhin หรือ Akshan</li><li><strong>Axiom Arcanist</strong>: เพิ่มดาเมจ การฮีล และโล่จากสกิลอัลติ 10% พร้อมลดคูลดาวน์อัลติ 5% เมื่อมีส่วนร่วมสังหารศัตรู เหมาะกับ Sivir หรือ Miss Fortune</li><li><strong>Unshakeable</strong>: เพิ่มพลังป้องกัน 5% และได้รับโบนัสเกราะ/ต้านเวทอีก 4% ต่อแชมเปี้ยนศัตรูที่อยู่ในระยะ (สูงสุด 3 ตัว) สำหรับสายแท็งก์อย่าง Ornn และ Poppy</li><li><strong>Chain Assault</strong>: แทนที่ Mark of the Weak เมื่อสกิลโดนศัตรูจะมาร์กเป้าหมาย และการโจมตีหรือสกิลต่อไป 2 ครั้งจะสร้างดาเมจเพิ่ม</li><li><strong>Tyrant</strong>: เพิ่มดาเมจเมื่อโจมตีแชมเปี้ยนที่มีพลังชีวิตต่ำกว่า 50% เหมาะกับสาย Burst เช่น Katarina</li></ul><p>รูนที่ถูกนำออกได้แก่ Mark of the Weak, Pathfinder, และ Onslaught</p><img src="https://media.online-station.net/images/2025/10/117209c46f88be37fcf77994e36701ea.jpg"><h2>อัปเดตสายซัพพอร์ต</h2><p>สายซัพพอร์ต Dragon Lane ได้รับการอัปเดตครั้งใหญ่ โดยเฉพาะสายแท็งก์กับไอเทมใหม่สุดโหด</p><h3>ไอเทมใหม่: Radiant Virtue</h3><p>เส้นทางการคราฟต์: Kindlegem + Chain Vest (ราคาทั้งหมด 2,850)</p><p><strong>ค่าสถานะ:</strong><br>+300 HP<br>+45 Armor<br>+15 Ability Haste</p><p><strong>Guiding Light:</strong> เมื่อใช้อัลติ จะได้รับพลังชีวิตสูงสุดเพิ่ม 12.5% เป็นเวลา 6 วินาที และฟื้นฟู HP ให้ตัวเองและพันธมิตรในระยะ 1200 หน่วย 3% ต่อวินาที (ลดลง 50% สำหรับแชมเปี้ยนระยะไกล)</p><p>นอกจากนี้ ทีมพัฒนายังได้ปรับสมดุล <strong>Dawnshroud</strong> และ <strong>Protector’s Vow</strong> ให้สอดคล้องกับเกมเพลย์ปัจจุบัน</p><h2>การปรับ Boot Enchantments</h2><p>หลังจากอัปเดตใน Patch 6.2 ทีมงานได้ติดตามผลและพบว่า Boot Enchantments บางชนิดมีฟังก์ชันซ้ำซ้อน จึงได้ทำการ “ตัดและปรับสมดุล” เพื่อให้แต่ละ Enchant โดดเด่นในจังหวะที่ถูกออกแบบมา พร้อมรีเวิร์ก <strong>Veil Enchantment</strong> ใหม่ทั้งหมด รายละเอียดฉบับเต็มจะเปิดเผยใน Patch Notes</p><h2>ฉลองครบรอบ 5 ปี</h2><p>เพื่อฉลองโอกาสพิเศษนี้ <strong>Wild Rift</strong> เตรียมจัดกิจกรรมสุดพิเศษ พร้อมของรางวัลมากมาย รวมถึงโหมด <em>Worlds-themed AAA ARAM</em>, มินิเกมใหม่ “SMASH” และของสะสมครบรอบปีจากทั่วทั้งจักรวาล Runeterra!</p></article>
','https://www.riotgames.com/darkroom/1440/08bcc251757a1f64e30e0d7e8c513d35:be16374e056f8268996ef96555c7a113/wr-cb1-announcementarticle-banner-1920x1080.png','อัปเดตเกม',now() - interval '1 week'),
('fc26newshirt','พร้อมลงสนามเกมใหญ่! PUMA และ แมนเชสเตอร์ ซิตี้ จับมือ EA SPORTS เปิดตัวชุดแข่งรุ่นพิเศษ FC26','<article><h1>PUMA x EA SPORTS FC x แมนเชสเตอร์ ซิตี้ เปิดตัวชุดแข่งรุ่นพิเศษพร้อมชิป NFC!</h1><p><strong>PUMA</strong> แบรนด์กีฬาระดับโลก <strong>EA SPORTS FC</strong> และสโมสรฟุตบอล <strong>แมนเชสเตอร์ ซิตี้</strong> ผนึกกำลังเปิดตัวชุดแข่งฟุตบอลและคอลเล็กชันไลฟ์สไตล์รุ่นพิเศษที่มาพร้อมนวัตกรรมใหม่ล่าสุด <strong>ชิป NFC (Near Field Communication)</strong> แบบกำหนดเองที่ฝังอยู่ในตราสโมสรบนเสื้อแข่ง โดยออกแบบมาเพื่อมอบประสบการณ์สุดพิเศษในการเชื่อมต่อกับทีม “เรือใบสีฟ้า” ทั้งในเกม <strong>EA SPORTS FC™ 26</strong> และในสนามฟุตบอลจริง</p><p>เทคโนโลยี NFC จะช่วยให้แฟนบอลสามารถเปิดประสบการณ์ดิจิทัลสุดพิเศษได้ด้วยการ “แตะสมาร์ทโฟน” บนตราสโมสร เพื่อเข้าถึงคอนเทนต์แบบเอ็กซ์คลูซีฟในเกม รวมถึงสิทธิพิเศษและกิจกรรมจากสโมสรฟุตบอล แมนเชสเตอร์ ซิตี้, PUMA และ EA SPORTS FC เปลี่ยนเสื้อแข่งให้กลายเป็น “ประตูสู่โลกอินเทอร์แอคทีฟ” อย่างแท้จริง</p><img src="https://www.mancity.com/meta/media/01sii5kx/25aw_pr_ts_football_man-city_ea-sports-fc_matchwear_product_kv_0002_16x9_1920x1080px.jpg?width=1620" alt="PUMA x EA SPORTS FC"><p>หัวใจสำคัญของการออกแบบชุดแข่งรุ่นพิเศษนี้คือ “<strong>รูปทรงสามเหลี่ยม</strong>” ซึ่งเป็นสัญลักษณ์อันทรงพลังที่สะท้อนตัวตนของแบรนด์ FC และสไตล์การเล่นของ แมนเชสเตอร์ ซิตี้ ชุดแข่งมาในโทนสี <em>Forest Green</em> ผสานกราฟิกสามเหลี่ยมสีเทอร์คอยซ์และเมทัลลิก พร้อมโลโก้ PUMA สีเมทัลลิก และชิป NFC ที่ฝังอยู่กลางตราสโมสร ภายใต้แนวคิด “<strong>The Club is yours, wherever the game takes you.</strong>”</p><p>มาร์โก มูลเลอร์ Senior Director of Product Line Management Performance Apparel ของ PUMA กล่าวว่า “วงการฟุตบอลกำลังพัฒนาไปข้างหน้าเช่นเดียวกับวิธีที่แฟนบอลเชื่อมต่อกับสโมสรของพวกเขา ความร่วมมือครั้งนี้ยกระดับมาตรฐานใหม่ของนวัตกรรมในวงการชุดแข่ง ผสานโลกแห่งความจริง โลกดิจิทัล และอารมณ์ความรู้สึกของแฟนบอลเข้าไว้ด้วยกัน เราภูมิใจที่ได้เห็นผลลัพธ์ที่โดดเด่นและพลิกโฉมการออกแบบชุดแข่งอย่างแท้จริง”</p><img src="https://www.mustplay.in.th/static/thumb/2025/9/15/attach-1760517325995.jpg" alt="Manchester City Esports"><p>ชอน “เชลซ์” สปริงเกตต์ นักกีฬาอีสปอร์ตจากทีมแมนเชสเตอร์ ซิตี้ Esports และแชมป์ ePremier League ฤดูกาล 2020/21 กล่าวว่า “เป็นเรื่องที่น่าทึ่งที่ได้เห็นแมนเชสเตอร์ ซิตี้ และ EA SPORTS FC ร่วมมือกันในคอลเล็กชันสุดพิเศษแบบนี้ สำหรับผมที่รักทั้งฟุตบอลและการเล่นเกม นวัตกรรมชิปอัจฉริยะแบบอินเทอร์แอคทีฟนับเป็นสิ่งที่เท่มาก เพราะช่วยให้เราได้เชื่อมต่อกับสโมสรผ่านทั้งสองสิ่งที่หลงใหล และที่สุดยอดไปกว่านั้นคือแฟนๆ ยังสามารถปลดล็อกของรางวัลพิเศษในเกมได้ด้วย”</p><p>เจมส์ เทย์เลอร์ Director of Football Partnerships ของ EA SPORTS FC กล่าวเพิ่มเติมว่า “เสื้อฟุตบอลเป็นสัญลักษณ์ของความภาคภูมิใจและสายสัมพันธ์ระหว่างสโมสรกับแฟนบอลเสมอมา และเราภูมิใจที่ได้นำจิตวิญญาณนี้เข้าสู่เกม EA SPORTS FC 26 ร่วมกับแมนเชสเตอร์ ซิตี้ และ PUMA เพื่อเปิดโอกาสให้แฟนๆ เชื่อมต่อกับสโมสรที่พวกเขารักได้ในมิติใหม่”</p><p>ชุดแข่งพิเศษของแมนเชสเตอร์ ซิตี้ และ EA SPORTS FC จะปรากฏในเกม <strong>EA SPORTS FC 26</strong> ตั้งแต่วันที่ 24 ตุลาคมนี้ โดยสามารถเลือกใช้ได้ในโหมด Kick Off, Career, Clubs และโหมดยอดนิยมอย่าง FUT ตั้งแต่วันที่ 19 พฤศจิกายน 2568 ถึง 19 มกราคม 2569 (เฉพาะผู้ที่ได้รับสิทธิ์)</p><p>แฟนบอลสามารถเข้าร่วมกิจกรรมพิเศษเพื่อรับของรางวัลในเกม EA SPORTS FC 26 ผ่านการสแกน NFC บนตราสโมสร โดยมี 2 รอบ ได้แก่ <br><strong>รอบแรก:</strong> 15 ตุลาคม – 10 พฤศจิกายน 2568<br><strong>รอบที่สอง:</strong> 11 พฤศจิกายน 2568 – 10 มกราคม 2569<br>ของรางวัลพิเศษประกอบด้วยชุดแข่งแมนเชสเตอร์ ซิตี้ ในโหมด FUT, ไอเท็มพิเศษใน Clubs และสิทธิ์เลือกนักเตะแบบยืมตัวสุดเอ็กซ์คลูซีฟ</p><img src="https://www.mustplay.in.th/static/thumb/2025/9/15/attach-1760517351839.jpg" alt="Man City x PUMA"><p>ชุดแข่งรุ่นพิเศษนี้จะถูกสวมใส่โดยทีมชายชุดใหญ่ของ แมนเชสเตอร์ ซิตี้ ในบางแมตช์ของศึก <strong>ยูฟ่าแชมเปียนส์ลีก</strong> ในฐานะทีมเยือน โดยจะประเดิมสนามครั้งแรกในการพบกับสโมสรฟุตบอลบิยาร์เรอัล ในคืนวันที่ 21 ตุลาคมนี้ ส่วนทีมฟุตบอลหญิงของสโมสรก็จะสวมชุดพิเศษนี้ในบางแมตช์ของการแข่งขันภายในประเทศตลอดทั้งฤดูกาล</p><p>คอลเล็กชันระหว่างแมนเชสเตอร์ ซิตี้ และ EA SPORTS FC วางจำหน่ายแล้ววันนี้ที่ร้าน <strong>ARI Football</strong>, <strong>Supersports</strong>, ร้านค้าอย่างเป็นทางการของสโมสร และร้านค้าชั้นนำทั่วโลก!</p></article>
','https://cf-images.eu-west-1.prod.boltdns.net/v1/static/10228001001/da99ade9-4a53-41f1-b373-1d29eb47c874/361595b8-d2e3-4374-aa3e-8fa931556d58/810x456/match/image.jpg','อัปเดตเกม',now() - interval '4 day')

